import os

code = '''
import os
import sys
import time
from datetime import datetime
from pathlib import Path

try:
    from PIL import ImageGrab, Image
    PIL_AVAILABLE = True
except ImportError:
    PIL_AVAILABLE = False

try:
    import mss
    import mss.tools
    MSS_AVAILABLE = True
except ImportError:
    MSS_AVAILABLE = False


class ScreenshotTool:
    """اداة لقطات الشاشة للوكيل - تدعم عدة مكتبات"""

    VERSION = "1.0.0"

    def __init__(self, output_dir=None):
        self.output_dir = Path(output_dir) if output_dir else Path("screenshots")
        self.output_dir.mkdir(parents=True, exist_ok=True)
        self.backend = self._detect_backend()
        print(f"[ScreenshotTool v{self.VERSION}] Backend: {self.backend}")

    def _detect_backend(self):
        if MSS_AVAILABLE:
            return "mss"
        elif PIL_AVAILABLE:
            return "pillow"
        else:
            return "none"

    def capture(self, region=None, filename=None):
        """التقاط لقطة شاشة
        Args:
            region: (x, y, width, height) او None للشاشة كاملة
            filename: اسم الملف (اختياري، يتم توليده تلقائياً)
        Returns:
            dict مع معلومات اللقطة
        """
        if not filename:
            ts = datetime.now().strftime("%Y%m%d_%H%M%S")
            filename = f"screenshot_{ts}.png"

        filepath = self.output_dir / filename
        result = {
            "success": False,
            "filepath": str(filepath),
            "filename": filename,
            "backend": self.backend,
            "timestamp": datetime.now().isoformat(),
            "region": region,
            "error": None
        }

        try:
            if self.backend == "mss":
                result = self._capture_mss(filepath, region, result)
            elif self.backend == "pillow":
                result = self._capture_pillow(filepath, region, result)
            else:
                result["error"] = "لا توجد مكتبة لقطات شاشة متاحة. ثبّت: pip install mss او pip install Pillow"
                return result
        except Exception as e:
            result["error"] = f"خطأ في الالتقاط: {str(e)}"

        return result

    def _capture_mss(self, filepath, region, result):
        with mss.mss() as sct:
            if region:
                x, y, w, h = region
                monitor = {"top": y, "left": x, "width": w, "height": h}
            else:
                monitor = sct.monitors[0]

            screenshot = sct.grab(monitor)
            mss.tools.to_png(screenshot.rgb, screenshot.size, output=str(filepath))

            result["success"] = True
            result["width"] = screenshot.width
            result["height"] = screenshot.height
            result["size_bytes"] = os.path.getsize(filepath)
        return result

    def _capture_pillow(self, filepath, region, result):
        if region:
            x, y, w, h = region
            bbox = (x, y, x + w, y + h)
            screenshot = ImageGrab.grab(bbox=bbox)
        else:
            screenshot = ImageGrab.grab()

        screenshot.save(str(filepath), "PNG")
        result["success"] = True
        result["width"] = screenshot.width
        result["height"] = screenshot.height
        result["size_bytes"] = os.path.getsize(filepath)
        return result

    def capture_multiple(self, count=3, delay=1.0):
        """التقاط عدة لقطات متتالية"""
        results = []
        for i in range(count):
            r = self.capture(filename=f"multi_{i+1}_{datetime.now().strftime(chr(37)+\'Y\'+chr(37)+\'m\'+chr(37)+\'d_\'+chr(37)+\'H\'+chr(37)+\'M\'+chr(37)+\'S\')}.png")
            results.append(r)
            if i < count - 1:
                time.sleep(delay)
        return results

    def get_screen_info(self):
        """معلومات عن الشاشات المتاحة"""
        info = {"backend": self.backend, "screens": []}
        try:
            if self.backend == "mss":
                with mss.mss() as sct:
                    for i, m in enumerate(sct.monitors):
                        info["screens"].append({
                            "index": i,
                            "top": m["top"],
                            "left": m["left"],
                            "width": m["width"],
                            "height": m["height"]
                        })
        except Exception as e:
            info["error"] = str(e)
        return info

    def check_availability(self):
        """فحص توفر مكتبات اللقطات"""
        return {
            "mss": MSS_AVAILABLE,
            "pillow": PIL_AVAILABLE,
            "active_backend": self.backend,
            "ready": self.backend != "none"
        }


if __name__ == "__main__":
    tool = ScreenshotTool()
    print("Availability:", tool.check_availability())
    if tool.backend != "none":
        result = tool.capture()
        print(f"Screenshot: {result}")
    else:
        print("No screenshot library available. Install: pip install mss")
'''

